            this.c_memno.DataMember = "Query";
            this.c_memno.Expression = "[MEMBER_GROUP_NO] + \'-\' + [CONTRACT_MEMNO]";
            this.c_memno.Name = "c_memno";
            // 
            // c_mem_name
            // 
            this.c_mem_name.DataMember = "Query";
            this.c_mem_name.Expression = "[MEMBER_NAME] + \' \' + \'(\' +[MEMBERSHIP_NO]+\'-\'+[MEMBER_GROUP_NO]+\')\'";
            this.c_mem_name.Name = "c_mem_name";
            // 
            // c_coll_name
            // 
            this.c_coll_name.DataMember = "Query";
            this.c_coll_name.Expression = "[COLLATERAL_DESCRIPTION] + \' \' +\'(\'+[REF_OWN_NO]+\'-\'+[COLL_GROUP_NO]+\')\'";
            this.c_coll_name.Name = "c_coll_name";
            // 
            // c_addr_1
            // 
            this.c_addr_1.DataMember = "Query";
            this.c_addr_1.Expression = "Iif([ADDRESS_NO] = \'-\', \'\' ,[ADDRESS_NO] )+ Iif([MOO]=\'-\', \'\' ,\' หมู่\' + [MOO] ) " +
    "+ Iif([TAMBOL]=\'-\', \'\' ,\' ต.\' +[TAMBOL] )";
            this.c_addr_1.Name = "c_addr_1";
            // 
            // c_addr_2
            // 
            this.c_addr_2.DataMember = "Query";
            this.c_addr_2.Expression = "Iif([DISTRICT]=\'-\', \'\' ,\'อ.\'+[DISTRICT] ) + Iif([PROVINCE]=\'-\',  \'\',\' จ.\'+[PROVIN" +
    "CE] )";
            this.c_addr_2.Name = "c_addr_2";
            // 
            // c_addr_3
            // 
            this.c_addr_3.DataMember = "Query";
            this.c_addr_3.Expression = "Iif([POSTCODE]=\'-\', \'\' ,\'รหัสไปรษณีย์ \' +[POSTCODE] )";
            this.c_addr_3.Name = "c_addr_3";
            // 
            // c_month
            // 
            this.c_month.DataMember = "Query";
            this.c_month.Expression = "[MONTH_NAME] + \' \' +[RECEIVE_YEAR]";
            this.c_month.Name = "c_month";
            // 
            // c_sum_prin_not
            // 
            this.c_sum_prin_not.DataMember = "Query";
            this.c_sum_prin_not.Expression = "[PRINCIPAL_OF_LOAN] - (IsNull([PRINCIPAL_NOT],0) + IsNull([UKPAID_AFTER_P],0) + I" +
    "sNull([UKPAID_AGENT_P],0))";
            this.c_sum_prin_not.Name = "c_sum_prin_not";
            // 
            // c_sum_int_not
            // 
            this.c_sum_int_not.DataMember = "Query";
            this.c_sum_int_not.Expression = "[INTEREST] - (IsNull([INTEREST_NOT],0) + IsNull([UKPAID_AFTER_I],0) + IsNull([UKP" +
    "AID_AGENT_I],0))";
            this.c_sum_int_not.Name = "c_sum_int_not";
